import React, { useState, useEffect, useRef } from 'react';
import { sendMessage, getSessions, getMessages } from '../api';
import { useAuth } from '../context/AuthContext';

export default function Chat() {
  const { user } = useAuth();
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState([]);
  const [sessionId, setSessionId] = useState(null);
  const [loading, setLoading] = useState(false);
  const [sessions, setSessions] = useState([]);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const bottomRef = useRef(null);

  useEffect(() => {
    getSessions().then(r => setSessions(r.data || [])).catch(() => {});
    // Welcome message
    setMessages([{
      id: 'welcome', role: 'assistant',
      content: `Hi ${user?.name?.split(' ')[0] || 'there'} 👋 I'm MindEase, your mental wellness companion. I'm here to listen and support you. How are you feeling today?`
    }]);
  }, [user?.name]);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, loading]);

  const loadSession = async (sid) => {
    try {
      const res = await getMessages(sid);
      const msgs = res.data || [];
      setMessages(msgs.length ? msgs : [{ id: 'welcome', role: 'assistant', content: 'What would you like to talk about?' }]);
      setSessionId(sid);
      setSidebarOpen(false);
    } catch {}
  };

  const send = async () => {
    const text = input.trim();
    if (!text || loading) return;
    setInput('');
    const userMsg = { id: Date.now(), role: 'user', content: text };
    setMessages(prev => [...prev, userMsg]);
    setLoading(true);
    try {
      const res = await sendMessage({ content: text, session_id: sessionId });
      setSessionId(res.data.session_id);
      setMessages(prev => [...prev, { id: res.data.ai_message.id, role: 'assistant', content: res.data.ai_message.content }]);
      getSessions().then(r => setSessions(r.data || [])).catch(() => {});
    } catch {
      setMessages(prev => [...prev, { id: Date.now() + 1, role: 'assistant', content: "I'm having trouble connecting right now. Please try again in a moment. If you're in crisis, please call iCall at 9152987821." }]);
    } finally { setLoading(false); }
  };

  const newChat = () => {
    setSessionId(null);
    setMessages([{ id: 'welcome', role: 'assistant', content: `Hi again! What's on your mind?` }]);
    setSidebarOpen(false);
  };

  const handleKey = (e) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); send(); } };

  const QUICK = ['I feel anxious about exams', 'I can\'t sleep well', 'I feel lonely', 'I need motivation'];

  return (
    <div style={styles.shell}>
      {/* Sessions sidebar */}
      {sidebarOpen && <div style={styles.overlay} onClick={() => setSidebarOpen(false)} />}
      <aside style={{ ...styles.sidebar, ...(sidebarOpen ? styles.sidebarVisible : {}) }}>
        <div style={styles.sidebarHeader}>
          <span style={{ fontWeight: 700, color: 'var(--ink)' }}>Chat History</span>
          <button style={styles.iconBtn} onClick={() => setSidebarOpen(false)}>✕</button>
        </div>
        <button className="btn-primary" style={{ margin: '12px 16px', fontSize: '0.85rem', padding: '9px 18px' }} onClick={newChat}>+ New Chat</button>
        <div style={styles.sessionList}>
          {sessions.length === 0 && <div style={styles.emptyState}>No previous sessions</div>}
          {sessions.map(s => (
            <div key={s.id} style={styles.sessionItem} onClick={() => loadSession(s.id)}>
              <div style={styles.sessionTitle}>Session #{s.id}</div>
              <div style={styles.sessionMeta}>{s.message_count} messages · {new Date(s.started_at).toLocaleDateString()}</div>
            </div>
          ))}
        </div>
      </aside>

      {/* Chat area */}
      <div style={styles.chatArea}>
        {/* Chat header */}
        <div style={styles.chatHeader}>
          <button style={styles.iconBtn} onClick={() => setSidebarOpen(true)}>☰</button>
          <div style={styles.chatHeaderInfo}>
            <div style={styles.botAvatar}>🌱</div>
            <div>
              <div style={styles.botName}>MindEase</div>
              <div style={styles.botStatus}><span style={styles.dot} />Online</div>
            </div>
          </div>
          <button className="btn-ghost" style={{ fontSize: '0.8rem', padding: '6px 14px' }} onClick={newChat}>New chat</button>
        </div>

        {/* Messages */}
        <div style={styles.messages}>
          {messages.map((msg, i) => (
            <div key={msg.id || i} style={{ ...styles.msgRow, ...(msg.role === 'user' ? styles.msgRowUser : {}) }}>
              {msg.role === 'assistant' && <div style={styles.msgAvatar}>🌱</div>}
              <div style={{ ...styles.bubble, ...(msg.role === 'user' ? styles.bubbleUser : styles.bubbleBot) }}>
                {msg.content}
              </div>
            </div>
          ))}
          {loading && (
            <div style={styles.msgRow}>
              <div style={styles.msgAvatar}>🌱</div>
              <div style={{ ...styles.bubble, ...styles.bubbleBot, ...styles.typing }}>
                <span style={styles.dot2} /><span style={{ ...styles.dot2, animationDelay: '0.2s' }} /><span style={{ ...styles.dot2, animationDelay: '0.4s' }} />
              </div>
            </div>
          )}
          <div ref={bottomRef} />
        </div>

        {/* Quick prompts */}
        {messages.length <= 1 && (
          <div style={styles.quickPrompts}>
            {QUICK.map(q => (
              <button key={q} style={styles.quickBtn} onClick={() => { setInput(q); }}>
                {q}
              </button>
            ))}
          </div>
        )}

        {/* Input */}
        <div style={styles.inputRow}>
          <textarea
            value={input} onChange={e => setInput(e.target.value)} onKeyDown={handleKey}
            placeholder="Share what's on your mind… (Enter to send)"
            rows={1} style={styles.textarea}
          />
          <button style={styles.sendBtn} onClick={send} disabled={loading || !input.trim()}>
            ↑
          </button>
        </div>
        <div style={styles.disclaimer}>MindEase provides emotional support, not professional therapy. In crisis, call iCall: 9152987821</div>
      </div>
    </div>
  );
}

